   OSBOOL extbit = FALSE;

   RTXCTXTPUSHTYPENAME (pctxt, "CriticalityDiagnostics-IE-Item");

   RTDIAGSTRM2 (pctxt, "asn1PE_CriticalityDiagnostics_IE_Item: start\n");

   extbit = (OSBOOL)(pvalue->extElem1.count > 0);

   /* extension bit */

   PU_NEWFIELD(pctxt, "extension bit");

   stat = rtxEncBit (pctxt, extbit);
   if (stat != 0) return LOG_RTERR (pctxt, stat);

   PU_SETBITCOUNT(pctxt);

   /* encode iECriticality */

   RTXCTXTPUSHELEMNAME (pctxt, "iECriticality");

   stat = asn1PE_Criticality (pctxt, pvalue->iECriticality);
   if (stat != 0) return LOG_RTERR (pctxt, stat);

